def process_batch(rows):
    ok, q = [], []
    for r in rows:
        if not r.get("id"):
            q.append({"id": None, "reason": "missing id"})
        else:
            ok.append(r)
    return {"ok": ok, "quarantined": q, "in": len(rows)}

rows = [{"id": 1}, {}, {"id": 2}]
print(process_batch(rows))

